#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int len = strlen(s);
        int aCount = 0, bCount = 0;
        for (int i = 0; i < len; i++) {
            if (s[i] == 'A') aCount++;
            else if (s[i] == 'B') bCount++;
        }
        if (aCount % 2 == bCount % 2) printf("A\n");
        else printf("B\n");
    }
    return 0;
}

