const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const s = readline();
    let aCount = 0, bCount = 0;
    for (let j = 0; j < s.length; j++) {
        if (s[j] === 'A') aCount++;
        else if (s[j] === 'B') bCount++;
    }
    if (aCount % 2 === bCount % 2) console.log('A');
    else console.log('B');
}
